import{_ as e,o as i,c as s,a2 as l}from"./chunks/framework.BKG_UbFK.js";const u=JSON.parse('{"title":"Публикация","description":"","frontmatter":{},"headers":[],"relativePath":"ru/guide/publishing.md","filePath":"ru/guide/publishing.md"}'),t={name:"ru/guide/publishing.md"};function n(o,a,c,h,d,r){return i(),s("div",null,[...a[0]||(a[0]=[l(`<h1 id="публикация" tabindex="-1">Публикация <a class="header-anchor" href="#публикация" aria-label="Permalink to &quot;Публикация&quot;">​</a></h1><p>Clearance публикует три вида ресурсов через теги <code>vendor:publish</code>: конфигурацию, миграции и переводы. Конфигурация и миграции обрабатываются автоматически установщиком (см. <a href="/clearance-docs/ru/guide/installation.html">Установку</a>); эта страница описывает их публикацию вручную, а также публикацию переводов.</p><h2 id="конфигурация" tabindex="-1">Конфигурация <a class="header-anchor" href="#конфигурация" aria-label="Permalink to &quot;Конфигурация&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vendor:publish</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tag=clearance-config</span></span></code></pre></div><p>Публикует <code>config/clearance.php</code> в ваше приложение. См. <a href="/clearance-docs/ru/guide/configuration.html">справочник конфигурации</a> для каждого ключа, его значения по умолчанию и назначения.</p><h2 id="переводы" tabindex="-1">Переводы <a class="header-anchor" href="#переводы" aria-label="Permalink to &quot;Переводы&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">php</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> artisan</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vendor:publish</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tag=clearance-translations</span></span></code></pre></div><p>Это копирует 9 языков в комплекте (<code>ar</code>, <code>en</code>, <code>es</code>, <code>fr</code>, <code>hi</code>, <code>it</code>, <code>pt</code>, <code>ru</code>, <code>zh</code>) в <code>lang/vendor/clearance/{locale}/ui.php</code> в вашем приложении. Чтобы добавить новую локаль или переопределить строки в существующей, добавьте туда каталог локали, используя <code>en/ui.php</code> как эталонный набор ключей. Все локали содержат идентичный набор ключей, что проверяется отдельным тестом при каждом изменении.</p><h2 id="переопределение-layout-панели" tabindex="-1">Переопределение layout панели <a class="header-anchor" href="#переопределение-layout-панели" aria-label="Permalink to &quot;Переопределение layout панели&quot;">​</a></h2><p>Ключ конфигурации <code>layout</code> управляет Blade-layout&#39;ом, используемым полностраничными компонентами:</p><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// config/clearance.php</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;layout&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> null</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// host app&#39;s default (config(&#39;livewire.layout&#39;))</span></span></code></pre></div><p>Оставьте <code>null</code>, чтобы использовать layout Livewire по умолчанию вашего приложения, либо укажите конкретное представление layout, чтобы отрендерить панель внутри собственной оболочки.</p><h2 id="миграции" tabindex="-1">Миграции <a class="header-anchor" href="#миграции" aria-label="Permalink to &quot;Миграции&quot;">​</a></h2><p>Миграции Clearance публикуются и выполняются автоматически командой <code>php artisan clearance:install</code> - установщик также публикует и запускает миграции Spatie первыми, если таблица <code>roles</code> ещё не существует. См. <a href="/clearance-docs/ru/guide/installation.html">Установку</a> для полного пошагового процесса и <a href="/clearance-docs/ru/guide/installation.html#run-the-installer">предупреждение</a> о том, что нельзя запускать обычный <code>migrate</code> на новой установке.</p><h2 id="смотрите-также" tabindex="-1">Смотрите также <a class="header-anchor" href="#смотрите-также" aria-label="Permalink to &quot;Смотрите также&quot;">​</a></h2><ul><li><a href="/clearance-docs/ru/guide/configuration.html">Справочник конфигурации</a> - каждый ключ конфигурации</li><li><a href="/clearance-docs/ru/guide/installation.html">Установка</a> - полный процесс установщика</li><li><a href="/clearance-docs/ru/guide/migration.html">Миграция</a> - <code>clearance:backfill</code> для существующих установок Spatie</li></ul>`,16)])])}const k=e(t,[["render",n]]);export{u as __pageData,k as default};
